/**
 * Fuzz tests for C++ stacks_queues (hard difficulty).
 *
 * Programs generated by an isolated instructor agent covering:
 * - Stack LIFO behaviour (drain order, size tracking)
 * - Queue FIFO behaviour with front() and back()
 * - queue::back() specifically (cpp_queue_back concept)
 * - Mixed stack/queue operations
 * - Two-stack queue simulation (with functions)
 * - Palindrome detection (parallel stack+queue)
 * - Sorted merge of two stacks into a queue
 *
 * Each test verifies:
 *   1. lift → generate round-trip produces semantically equivalent code
 *   2. Key container concepts are present in the semantic tree
 *
 * Note on cpp_queue_back lift: q.back() lifts to cpp_vector_back (shared
 * method name). The generate path from cpp_vector_back still emits .back(),
 * so round-trip output is correct even though the conceptId differs.
 * fuzz_2, fuzz_6, fuzz_9 document this expected degradation.
 */
import { describe, it, expect, beforeAll } from 'vitest'
import { Parser, Language } from 'web-tree-sitter'
import { createTestLifter } from '../helpers/setup-lifter'
import type { Lifter } from '../../src/core/lift/lifter'
import { registerCppLanguage } from '../../src/languages/cpp/generators'
import { generateCode } from '../../src/core/projection/code-generator'
import { setupTestRenderer } from '../helpers/setup-renderer'
import { execSync } from 'child_process'
import { writeFileSync, mkdirSync } from 'fs'
import type { StylePreset } from '../../src/core/types'
import type { SemanticNode } from '../../src/core/semantic-tree'

const style: StylePreset = {
  id: 'apcs', name: { 'zh-TW': 'APCS', en: 'APCS' },
  io_style: 'cout', naming_convention: 'camelCase',
  indent_size: 4, brace_style: 'K&R',
  namespace_style: 'using', header_style: 'individual',
}

let tsParser: Parser
let lifter: Lifter

beforeAll(async () => {
  await Parser.init({
    locateFile: (s: string) => `${process.cwd()}/public/${s}`,
  })
  tsParser = new Parser()
  const lang = await Language.load(`${process.cwd()}/public/tree-sitter-cpp.wasm`)
  tsParser.setLanguage(lang)
  lifter = createTestLifter()
  registerCppLanguage()
  setupTestRenderer()
})

function liftCode(code: string): SemanticNode | null {
  const tree = tsParser.parse(code)
  return lifter.lift(tree.rootNode as any)
}

function findConcept(node: SemanticNode | null, conceptId: string): SemanticNode | null {
  if (!node) return null
  if (node.concept === conceptId) return node
  for (const children of Object.values(node.children ?? {})) {
    for (const child of children as SemanticNode[]) {
      const found = findConcept(child, conceptId)
      if (found) return found
    }
  }
  return null
}

function collectConcepts(node: SemanticNode | null, result: Set<string> = new Set()): Set<string> {
  if (!node) return result
  result.add(node.concept)
  for (const children of Object.values(node.children ?? {})) {
    for (const child of children as SemanticNode[]) {
      collectConcepts(child, result)
    }
  }
  return result
}

function runCpp(code: string): string | null {
  try {
    mkdirSync('/tmp/semorphe-fuzz', { recursive: true })
    const src = `/tmp/semorphe-fuzz/rt_test_${Date.now()}.cpp`
    const bin = src.replace('.cpp', '')
    writeFileSync(src, code)
    execSync(`g++ -std=c++17 -o ${bin} ${src}`, { encoding: 'utf-8', stdio: 'pipe' })
    return execSync(bin, { encoding: 'utf-8', timeout: 5000 })
  } catch {
    return null
  }
}

// ─── fuzz_1: Stack LIFO drain ─────────────────────────────────────────────────

describe('fuzz_1: stack LIFO drain with size tracking', () => {
  const code = `#include <iostream>
#include <stack>
using namespace std;
int main() {
    stack<int> s;
    for (int i = 1; i <= 5; i++) s.push(i);
    cout << s.size() << endl;
    while (!s.empty()) {
        cout << s.top() << endl;
        s.pop();
    }
    cout << s.size() << endl;
    return 0;
}`

  it('should lift stack declare and operations', () => {
    const tree = liftCode(code)
    expect(tree).not.toBeNull()
    const concepts = collectConcepts(tree)
    expect(concepts.has('cpp_stack_declare')).toBe(true)
    expect(concepts.has('cpp_stack_top')).toBe(true)
  })

  it('should generate compilable code producing same output (PASS)', () => {
    const tree = liftCode(code)
    expect(tree).not.toBeNull()
    const generated = generateCode(tree!, 'cpp', style)
    const actual = runCpp(generated)
    const expected = runCpp(code)
    expect(actual).not.toBeNull()
    expect(actual?.trim()).toBe(expected?.trim())
  })
})

// ─── fuzz_2: Queue front/back tracking ────────────────────────────────────────

describe('fuzz_2: queue front() and back() after partial drain', () => {
  const code = `#include <iostream>
#include <queue>
using namespace std;
int main() {
    queue<int> q;
    q.push(10); q.push(20); q.push(30);
    cout << q.front() << endl; cout << q.back() << endl;
    q.pop();
    cout << q.front() << endl; cout << q.back() << endl;
    q.pop();
    cout << q.front() << endl; cout << q.back() << endl;
    return 0;
}`

  it('should lift queue declare and front/back concepts', () => {
    const tree = liftCode(code)
    expect(tree).not.toBeNull()
    const concepts = collectConcepts(tree)
    expect(concepts.has('cpp_queue_declare')).toBe(true)
    expect(concepts.has('cpp_queue_front')).toBe(true)
    // back() lifts to cpp_vector_back (shared method — known design decision)
    expect(concepts.has('cpp_vector_back')).toBe(true)
  })

  it('should generate compilable code producing same output (PASS — back() via cpp_vector_back)', () => {
    const tree = liftCode(code)
    expect(tree).not.toBeNull()
    const generated = generateCode(tree!, 'cpp', style)
    const actual = runCpp(generated)
    const expected = runCpp(code)
    expect(actual).not.toBeNull()
    expect(actual?.trim()).toBe(expected?.trim())
  })
})

// ─── fuzz_3: Interleaved stack and queue ──────────────────────────────────────

describe('fuzz_3: interleaved stack (LIFO) and queue (FIFO) side by side', () => {
  const code = `#include <iostream>
#include <stack>
#include <queue>
using namespace std;
int main() {
    stack<int> s;
    queue<int> q;
    for (int i = 1; i <= 4; i++) { s.push(i * 10); q.push(i * 10); }
    while (!s.empty() && !q.empty()) {
        cout << s.top() << " " << q.front() << endl;
        s.pop(); q.pop();
    }
    return 0;
}`

  it('should lift both stack and queue declare', () => {
    const tree = liftCode(code)
    expect(tree).not.toBeNull()
    const concepts = collectConcepts(tree)
    expect(concepts.has('cpp_stack_declare')).toBe(true)
    expect(concepts.has('cpp_queue_declare')).toBe(true)
  })

  it('should generate compilable code producing same output (PASS)', () => {
    const tree = liftCode(code)
    expect(tree).not.toBeNull()
    const generated = generateCode(tree!, 'cpp', style)
    const actual = runCpp(generated)
    const expected = runCpp(code)
    expect(actual).not.toBeNull()
    expect(actual?.trim()).toBe(expected?.trim())
  })
})

// ─── fuzz_4: Stack reverses queue ─────────────────────────────────────────────

describe('fuzz_4: use stack as intermediary to reverse a queue', () => {
  const code = `#include <iostream>
#include <stack>
#include <queue>
using namespace std;
int main() {
    queue<int> q; stack<int> s;
    for (int i = 1; i <= 6; i++) q.push(i);
    while (!q.empty()) { s.push(q.front()); q.pop(); }
    while (!s.empty()) { q.push(s.top()); s.pop(); }
    while (!q.empty()) { cout << q.front() << endl; q.pop(); }
    return 0;
}`

  it('should lift queue front() and stack top()', () => {
    const tree = liftCode(code)
    expect(tree).not.toBeNull()
    const concepts = collectConcepts(tree)
    expect(concepts.has('cpp_queue_declare')).toBe(true)
    expect(concepts.has('cpp_stack_declare')).toBe(true)
    expect(concepts.has('cpp_queue_front')).toBe(true)
    expect(concepts.has('cpp_stack_top')).toBe(true)
  })

  it('should generate compilable code producing same output (PASS)', () => {
    const tree = liftCode(code)
    expect(tree).not.toBeNull()
    const generated = generateCode(tree!, 'cpp', style)
    const actual = runCpp(generated)
    const expected = runCpp(code)
    expect(actual).not.toBeNull()
    expect(actual?.trim()).toBe(expected?.trim())
  })
})

// ─── fuzz_6: queue back() after rapid push-pop cycles ─────────────────────────

